    44	/// Return the first parser that can parse the given path.
    45	pub fn parser_for_path<'a>(
    46	    parsers: &'a [Box<dyn SessionParser>],
    47	    path: &Path,
    48	) -> Option<&'a dyn SessionParser> {
    49	    parsers
    50	        .iter()
    51	        .find(|parser| parser.can_parse(path))
    52	        .map(|parser| parser.as_ref())
    53	}
    54	
    55	/// Parse one path with the default parser set.
    56	///
    57	/// Returns `Ok(None)` when no parser matches the input path.
    58	pub fn parse_with_default_parsers(path: &Path) -> Result<Option<Session>> {
    59	    let parsers = all_parsers();
    60	    let Some(parser) = parser_for_path(&parsers, path) else {
    61	        return Ok(None);
    62	    };
    63	    let session = parser.parse(path)?;
    64	    Ok(Some(session))
    65	}
