   411	pub async fn run_scheduler(
   412	    config: DaemonConfig,
   413	    mut rx: mpsc::UnboundedReceiver<FileChangeEvent>,
   414	    mut shutdown: tokio::sync::watch::Receiver<bool>,
   415	    db: std::sync::Arc<LocalDb>,
