   421	        Ok(registry) => registry,
   422	        Err(e) => {
   423	            warn!("failed to load repo registry: {e}");
   424	            RepoRegistry::default()
   425	        }
   426	    };
   427	
   428	    // Run lifecycle cleanup once at startup before interval-driven cycles.
   429	    run_lifecycle_cleanup_on_start(&config, &db, &repo_registry);
   430	
   431	    // Pending changes: path -> when we last saw a change
   432	    let mut pending: HashMap<PathBuf, Instant> = HashMap::new();
   433	
   434	    let mut tick = tokio::time::interval(Duration::from_secs(1));
   435	    let retention_schedule = resolve_git_retention_schedule(&config);
   436	    let mut next_retention_run = retention_schedule.map(|(_, interval)| Instant::now() + interval);
   437	    let lifecycle_interval = resolve_lifecycle_schedule(&config);
   438	    let mut next_lifecycle_run = lifecycle_interval.map(|interval| Instant::now() + interval);
   439	
   440	    loop {
   441	        tokio::select! {
   442	            // Receive new file change events
   443	            Some(event) = rx.recv() => {
   444	                debug!("Scheduling: {:?}", event.path.display());
   445	                pending.insert(event.path, Instant::now());
   446	            }
   447	
   448	            // Periodic tick to check for debounced items
   449	            _ = tick.tick() => {
   450	                let now = Instant::now();
   451	                let effective_debounce = match effective_mode {
   452	                    PublishMode::Realtime => Duration::from_millis(config.daemon.realtime_debounce_ms),
   453	                    _ => debounce_duration,
   454	                };
   455	
   456	                let ready: Vec<PathBuf> = pending
   457	                    .iter()
   458	                    .filter(|(_, last_change)| now.duration_since(**last_change) >= effective_debounce)
   459	                    .map(|(path, _)| path.clone())
   460	                    .collect();
   461	
   462	                for path in ready {
   463	                    pending.remove(&path);
   464	                    if matches!(effective_mode, PublishMode::Manual) {
