   472	                        &config,
   473	                        &db,
   474	                        &mut repo_registry,
   475	                        should_auto_upload(&effective_mode),
   476	                    )
   477	                    .await;
   478	                    if let Err(e) = process_result {
   479	                        error!("Failed to process {}: {:#}", path.display(), e);
   480	                    }
   481	                }
   482	
   483	                if let (Some((keep_days, interval)), Some(next_at)) =
   484	                    (retention_schedule, next_retention_run)
   485	                {
   486	                    if now >= next_at {
   487	                        let retention_result = run_git_retention_once(&repo_registry, keep_days);
   488	                        if let Err(e) = retention_result {
   489	                            warn!("Git retention scan failed: {e}");
   490	                        }
   491	                        next_retention_run = Some(now + interval);
   492	                    }
   493	                }
   494	
   495	                if let (Some(interval), Some(next_at)) = (lifecycle_interval, next_lifecycle_run) {
   496	                    if now >= next_at {
   497	                        let cleanup_result =
   498	                            run_lifecycle_cleanup_once(&config, &db, &repo_registry);
   499	                        if let Err(e) = cleanup_result {
