   510	                let should_shutdown = {
   511	                    let borrowed = shutdown.borrow();
   512	                    *borrowed
   513	                };
   514	                if should_shutdown {
   515	                    info!("Scheduler shutting down");
   516	                    break;
   517	                }
   518	            }
   519	        }
   520	    }
   521	}
