   851	                "Stored session {} to git ref {} at {}",
   852	                session.session_id, stored.ref_name, stored.hail_path
   853	            );
   854	            // Try to generate raw URL from git remote
   855	            let body_url = git_ctx.remote.as_ref().map(|remote| {
   856	                opensession_git_native::generate_raw_url(
