   141	/// Codex stores sessions as JSONL files under ~/.codex/sessions/YYYY/MM/DD/rollout-*.jsonl
   142	fn find_codex_sessions(home: &std::path::Path) -> Vec<PathBuf> {
   143	    let mut roots = Vec::new();
   144	    if let Ok(codex_home) = std::env::var("CODEX_HOME") {
   145	        let codex_home = codex_home.trim();
   146	        if !codex_home.is_empty() {
   147	            roots.push(PathBuf::from(codex_home).join("sessions"));
   148	        }
   149	    }
   150	    roots.push(home.join(".codex").join("sessions"));
   151	
   152	    let mut seen = HashSet::new();
   153	    let mut out = Vec::new();
   154	    for root in roots {
   155	        if !root.exists() {
   156	            continue;
   157	        }
   158	        for path in find_files_with_ext(&root, "jsonl") {
   159	            if !is_codex_rollout_session_file(&path) {
   160	                continue;
   161	            }
   162	            if seen.insert(path.clone()) {
   163	                out.push(path);
   164	            }
   165	        }
   166	    }
   167	    out
   168	}
