   111	/// Read PID from pid file
   112	fn read_pid() -> Result<Option<u32>> {
   113	    let path = pid_file_path()?;
   114	    if !path.exists() {
   115	        return Ok(None);
   116	    }
   117	    let content = std::fs::read_to_string(&path).context("Failed to read PID file")?;
   118	    let pid: u32 = content.trim().parse().context("Invalid PID in pid file")?;
   119	    Ok(Some(pid))
   120	}
