   130	/// Check if a process with the given PID is running
   131	fn is_process_running(pid: u32) -> bool {
   132	    #[cfg(unix)]
   133	    {
   134	        process_exists_unix(pid)
   135	    }
   136	    #[cfg(not(unix))]
   137	    {
   138	        std::process::Command::new("tasklist")
   139	            .args(["/FI", &format!("PID eq {}", pid), "/NH"])
   140	            .output()
   141	            .map(|o| String::from_utf8_lossy(&o.stdout).contains(&pid.to_string()))
   142	            .unwrap_or(false)
   143	    }
   144	}
