   146	#[cfg(unix)]
   147	fn process_exists_unix(pid: u32) -> bool {
   148	    // SAFETY: kill(pid, 0) does not deliver a signal. It is the standard Unix probe for
   149	    // process existence and permissions, and we pass the parsed PID value directly to libc.
   150	    let rc = unsafe { libc::kill(pid as i32, 0) };
   151	    if rc == 0 {
   152	        return true;
   153	    }
   154	
   155	    matches!(
   156	        std::io::Error::last_os_error().raw_os_error(),
   157	        Some(libc::EPERM)
   158	    )
   159	}
   160	
   161	#[cfg(unix)]
   162	fn terminate_process_unix(pid: u32) {
   163	    // SAFETY: sending SIGTERM to a parsed PID delegates to the OS for permission and existence
   164	    // checks. The libc call does not outlive borrowed data and has no Rust aliasing concerns.
   165	    unsafe {
   166	        libc::kill(pid as i32, libc::SIGTERM);
   167	    }
   168	}
