   170	/// Find the daemon binary, looking next to the CLI binary first
   171	fn find_daemon_binary() -> Result<PathBuf> {
   172	    // Look next to our own binary
   173	    if let Ok(current_exe) = std::env::current_exe() {
   174	        let dir = current_exe.parent().unwrap_or(std::path::Path::new("."));
   175	        let daemon_path = dir.join("opensession-daemon");
   176	        if daemon_path.exists() {
   177	            return Ok(daemon_path);
   178	        }
   179	        // Try with .exe on Windows
   180	        let daemon_path = dir.join("opensession-daemon.exe");
   181	        if daemon_path.exists() {
   182	            return Ok(daemon_path);
   183	        }
   184	    }
   185	
   186	    // Try PATH without shelling out to `which` for portability.
   187	    if let Some(path) = find_in_path("opensession-daemon", std::env::var_os("PATH").as_deref()) {
